import { useEffect, useState } from "react";
import axios from "axios";
import Navbar from "../components/Navbar";

export default function LabourDashboard() {

  const user = JSON.parse(localStorage.getItem("user") || "{}");

  const [requests, setRequests] = useState([]);
  const [price, setPrice] = useState({});

  useEffect(() => {
    getRequests();
  }, []);

  const getRequests = async () => {
    try {
      const res = await axios.get(
        `http://localhost:5000/api/request/labour/${user._id}`
      );
      setRequests(res.data);
    } catch (err) {
      console.log(err);
    }
  };

  const respondRequest = async (id, action) => {
    try {
      await axios.put(
        `http://localhost:5000/api/request/labour-response/${id}`,
        {
          price: price[id] || "",
          action
        }
      );
      getRequests();
    } catch (err) {
      console.log(err);
    }
  };

  // ⭐ FIXED: rating stays after submit
  const submitFeedback = async (id, rating, comment) => {
    if (!rating || !comment) {
      return alert("Please give rating and review");
    }

    try {
      await axios.put(
        `http://localhost:5000/api/request/feedback/${id}`,
        {
          rating: Number(rating),
          comment
        }
      );

      setRequests((prev) =>
        prev.map((req) =>
          req._id === id
            ? {
                ...req,
                feedback: {
                  rating: Number(rating),
                  comment
                }
              }
            : req
        )
      );

    } catch (err) {
      console.log(err);
    }
  };

  return (
    <div style={styles.page}>
      <Navbar />

      <div style={styles.container}>
        <h2 style={styles.heading}>Incoming Requests</h2>

        {requests.length === 0 && (
          <p style={styles.empty}>No requests found</p>
        )}

        {requests.map((req) => (
          <div key={req._id} style={styles.card}>

            {/* HEADER */}
            <div style={styles.header}>
              <h3 style={styles.name}>{req.customerName}</h3>
              <span style={styles.badge}>{req.status}</span>
            </div>

            {/* DETAILS */}
            <div style={styles.details}>
              <p>Work: {req.workType}</p>
              <p>Location: {req.location}</p>
              <p>Date: {req.date}</p>
              <p>Decision: {req.customerDecision}</p>
            </div>

            {/* PRICE INPUT */}
            <div style={styles.field}>
              <input
                type="text"
                inputMode="numeric"
                placeholder="Enter Price (₹)"
                style={styles.input}
                value={price[req._id] || ""}
                onChange={(e) => {
                  const value = e.target.value.replace(/\D/g, "");
                  setPrice({
                    ...price,
                    [req._id]: value
                  });
                }}
              />
            </div>

            {/* BUTTONS */}
            {req.status === "Pending" && (
              <div style={styles.buttonRow}>
                <button
                  style={styles.acceptBtn}
                  onClick={() => respondRequest(req._id, "Accepted")}
                >
                  Accept
                </button>

                <button
                  style={styles.rejectBtn}
                  onClick={() => respondRequest(req._id, "Rejected")}
                >
                  Reject
                </button>
              </div>
            )}

            {/* ⭐ STAR FEEDBACK DISPLAY */}
            {req.feedback && (
              <div style={styles.feedbackBox}>

                <div style={styles.starRow}>
                  {[1, 2, 3, 4, 5].map((star) => (
                    <span
                      key={star}
                      style={{
                        fontSize: "20px",
                        color:
                          req.feedback.rating >= star
                            ? "#facc15"
                            : "#374151"
                      }}
                    >
                      ★
                    </span>
                  ))}
                </div>

                <p style={styles.comment}>
                  {req.feedback.comment}
                </p>

              </div>
            )}

          </div>
        ))}
      </div>
    </div>
  );
}

/* ================= FINAL UI ================= */

const styles = {

  page: {
    background: "#0b0f19",
    minHeight: "100vh",
    color: "white",
    fontFamily: "Arial"
  },

  container: {
    maxWidth: "850px",
    margin: "auto",
    padding: "20px"
  },

  heading: {
    textAlign: "center",
    marginBottom: "20px",
    fontSize: "20px"
  },

  /* 🟠 ORANGE CARD */
  card: {
    background: "#111827",
    border: "2px solid #f97316",
    borderRadius: "14px",
    padding: "16px",
    marginBottom: "14px",
    display: "flex",
    flexDirection: "column",
    gap: "12px"
  },

  header: {
    display: "flex",
    justifyContent: "space-between",
    alignItems: "center"
  },

  name: {
    margin: 0,
    fontSize: "16px"
  },

  badge: {
    background: "#1f2937",
    color: "#9ca3af",
    padding: "4px 10px",
    borderRadius: "6px",
    fontSize: "12px"
  },

  details: {
    display: "grid",
    gridTemplateColumns: "1fr 1fr",
    gap: "6px",
    fontSize: "13px",
    color: "#cbd5e1"
  },

  field: {
    width: "100%"
  },

  input: {
    width: "100%",
    height: "42px",
    padding: "10px 12px",
    borderRadius: "8px",
    border: "1px solid #374151",
    background: "#0f172a",
    color: "white",
    outline: "none",
    fontSize: "14px",
    boxSizing: "border-box"
  },

  buttonRow: {
    display: "flex",
    gap: "10px"
  },

  acceptBtn: {
    flex: 1,
    padding: "10px",
    background: "#16a34a",
    border: "none",
    borderRadius: "8px",
    color: "white",
    cursor: "pointer"
  },

  rejectBtn: {
    flex: 1,
    padding: "10px",
    background: "#dc2626",
    border: "none",
    borderRadius: "8px",
    color: "white",
    cursor: "pointer"
  },

  feedbackBox: {
    marginTop: "10px",
    padding: "10px",
    background: "#0f172a",
    border: "1px solid #374151",
    borderRadius: "8px"
  },

  starRow: {
    display: "flex",
    gap: "3px",
    marginBottom: "5px"
  },

  comment: {
    color: "#9ca3af",
    fontSize: "13px"
  },

  empty: {
    textAlign: "center",
    color: "#9ca3af"
  }
};
